parameters.jsCode:
const subscriber = $('Get Active Subscribers').item.json;
const allListings = $('Get This Week\'s New Listings').all().map(i => i.json);

// Filter listings based on subscriber preferences
let personalizedListings = allListings.filter(listing => {
  if (subscriber.province_preference && subscriber.province_preference !== 'all') {
    if (listing.province !== subscriber.province_preference) return false;
  }
  if (subscriber.max_budget && listing.price > subscriber.max_budget) return false;
  if (subscriber.min_bedrooms && listing.bedrooms < subscriber.min_bedrooms) return false;
  if (subscriber.property_type_preference && subscriber.property_type_preference !== 'all') {
    if (listing.property_type !== subscriber.property_type_preference) return false;
  }
  return true;
});

// If too few matches, show general listings
if (personalizedListings.length < 3) {
  personalizedListings = allListings.slice(0, 6);
}

// Limit to 6 featured listings
const featured = personalizedListings.slice(0, 6);

if (featured.length === 0) return [];

const firstName = subscriber.first_name || 'Property Seeker';
const weekOf = new Date().toLocaleDateString('en-ZA', { day: 'numeric', month: 'long', year: 'numeric' });

const unsubUrl = `https://puraestate.co.za/unsubscribe?email=${encodeURIComponent(subscriber.email)}&token=TOKEN_PLACEHOLDER`;

const emailHtml = `
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>PuraEstate Weekly Digest</title>
<style>
* { box-sizing: border-box; margin: 0; padding: 0; }
body { background: #f4f4f4; font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; }
.wrapper { max-width: 680px; margin: 0 auto; }
.header { background: linear-gradient(135deg, #1a472a, #2d6a4f); padding: 40px 30px; text-align: center; }
.logo { color: white; font-size: 28px; font-weight: 900; letter-spacing: 2px; }
.logo span { color: #95d5b2; }
.header-subtitle { color: rgba(255,255,255,0.8); margin-top: 8px; font-size: 14px; }
.hero { background: white; padding: 30px; text-align: center; border-bottom: 3px solid #e8f5e9; }
.hero h2 { color: #1a472a; font-size: 22px; }
.hero p { color: #666; margin-top: 8px; }
.listings-grid { background: #f9f9f9; padding: 20px; }
.listing-card { background: white; border-radius: 10px; margin: 12px 0; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.08); }
.listing-body { padding: 18px; }
.listing-title { font-size: 16px; font-weight: bold; color: #1a472a; margin-bottom: 6px; }
.listing-price { font-size: 22px; font-weight: 900; color: #2d6a4f; margin: 8px 0; }
.listing-meta { color: #777; font-size: 13px; display: flex; gap: 12px; flex-wrap: wrap; margin: 8px 0; }
.meta-tag { background: #e8f5e9; color: #1a472a; padding: 3px 10px; border-radius: 12px; font-size: 12px; }
.listing-location { color: #555; font-size: 13px; margin: 6px 0; }
.view-btn { display: inline-block; background: #1a472a; color: white; padding: 10px 22px; text-decoration: none; border-radius: 6px; font-size: 14px; font-weight: bold; margin-top: 10px; }
.footer { background: #1a472a; color: rgba(255,255,255,0.7); padding: 25px 30px; text-align: center; font-size: 12px; }
.footer a { color: #95d5b2; }
</style>
</head>
<body>
<div class="wrapper">
  <div class="header">
    <div class="logo">PURA<span>ESTATE</span></div>
    <div class="header-subtitle">Your Weekly Property Digest - Week of ${weekOf}</div>
  </div>
  <div class="hero">
    <h2>Hi ${firstName}, ${featured.length} new listings for you</h2>
    <p>${personalizedListings.length} properties match your preferences this week.</p>
  </div>
  <div class="listings-grid">
    ${featured.map(listing => `
    <div class="listing-card">
      <div class="listing-body">
        <div class="listing-title">${listing.title}</div>
        <div class="listing-price">R ${Number(listing.price).toLocaleString()}</div>
        <div class="listing-meta">
          ${listing.bedrooms > 0 ? `<span class="meta-tag">${listing.bedrooms} Bed</span>` : ''}
          ${listing.bathrooms > 0 ? `<span class="meta-tag">${listing.bathrooms} Bath</span>` : ''}
          ${listing.property_type ? `<span class="meta-tag" style="text-transform:capitalize">${listing.property_type}</span>` : ''}
          ${listing.size_sqm > 0 ? `<span class="meta-tag">${listing.size_sqm} m²</span>` : ''}
        </div>
        <div class="listing-location">${listing.suburb ? listing.suburb + ', ' : ''}${listing.city}, ${listing.province}</div>
        <a href="${listing.url}" class="view-btn">View Property</a>
      </div>
    </div>`).join('')}
  </div>
  <div style="background:white;padding:25px 30px;text-align:center;">
    <a href="https://puraestate.co.za/properties" style="background:#2d6a4f;color:white;padding:14px 35px;text-decoration:none;border-radius:6px;font-size:16px;font-weight:bold;display:inline-block;">Browse All Listings</a>
  </div>
  <div class="footer">
    <p>You're receiving this because you subscribed to PuraEstate property alerts.</p>
    <p style="margin-top:8px;"><a href="${unsubUrl}">Unsubscribe</a> | <a href="https://puraestate.co.za/preferences">Manage Preferences</a></p>
    <p style="margin-top:8px;">PuraEstate - South African Property Intelligence</p>
  </div>
</div>
</body>
</html>`;

return [{
  json: {
    subscriber_id: subscriber.id,
    email: subscriber.email,
    first_name: firstName,
    subject: `${featured.length} New Properties in ${subscriber.province_preference || 'South Africa'} - This Week`,
    email_html: emailHtml,
    listings_count: featured.length
  }
}];

